rules.mqtt_raw_to_jsonb:
{
    "id": "mqtt_raw_to_jsonb",
    "sql": "SELECT now() as time, meta(topic) as topic, to_json(*) as raw_payload, false as processed FROM mqtt_stream",
    "actions": [{
      "sql": {
        "dburl": "postgres://postgres:postgres@dispatching-postgres:5432/dispatching?sslmode=disable",
        "table": "telemetry.mqtt_raw_data"
      }
    }]
  }

rules.rule_downsample_fuel:
{
    "id": "rule_downsample_fuel",
    "sql": "SELECT * FROM local_stream_fuel_ds WHERE lag(data->fuel, 1, 0) = 0 OR abs(data->fuel - lag(data->fuel, 1, 0)) / lag(data->fuel, 1, 1) <= 0.5",
    "actions": [{
      "mqtt": {
        "server": "tcp://nanomq:1883",
        "topic": "truck/VEHICLE_ID_PLACEHOLDER/sensor/fuel/ds",
        "qos": 0,
        "sendSingle": true
      }
    }]
  }

rules.rule_downsample_speed:
{
    "id": "rule_downsample_speed",
    "sql": "SELECT * FROM local_stream_speed_ds WHERE (data->speed > 0 OR lag(data->speed, 1, 0) = 0) AND (lag(data->speed, 1, 0) = 0 OR abs(data->speed - lag(data->speed, 1, 0)) / lag(data->speed, 1, 1) <= 0.5)",
    "actions": [{
      "mqtt": {
        "server": "tcp://nanomq:1883",
        "topic": "truck/VEHICLE_ID_PLACEHOLDER/sensor/speed/ds",
        "qos": 0,
        "sendSingle": true
      }
    }]
  }

rules.rule_downsample_weight:
{
    "id": "rule_downsample_weight",
    "sql": "SELECT * FROM local_stream_weight_ds WHERE lag(data->weight, 1, 0) = 0 OR abs(data->weight - lag(data->weight, 1, 0)) / CASE WHEN lag(data->weight, 1, 1) = 0 THEN 1 ELSE lag(data->weight, 1, 1) END <= 0.5",
    "actions": [{
      "mqtt": {
        "server": "tcp://nanomq:1883",
        "topic": "truck/VEHICLE_ID_PLACEHOLDER/sensor/weight/ds",
        "qos": 0,
        "sendSingle": true
      }
    }]
  }

rules.rule_fuel_alerts:
{
    "id": "rule_fuel_alerts",
    "sql": "SELECT metadata->timestamp as timestamp, metadata->bort as vehicle_id, 'fuel' as sensor_type, data->fuel as fuel_level FROM local_stream_fuel_ds WHERE data->fuel < 10 GROUP BY TUMBLINGWINDOW(ss, 2)",
    "actions": [{
      "mqtt": {
        "server": "tcp://nanomq:1883",
        "topic": "truck/VEHICLE_ID_PLACEHOLDER/sensor/fuel/alerts",
        "qos": 0,
        "sendSingle": true,
        "dataTemplate": "{\"metadata\":{\"vehicle_id\":\"{{.vehicle_id}}\",\"sensor_type\":\"{{.sensor_type}}\",\"timestamp\":{{.timestamp}}},\"data\":{\"status\":\"alert_level\",\"value\":\"{{.fuel_level}}%\"}}"
      }
    }]
  }

