rules.rule_vibro_events:
{
    "id": "rule_vibro_events",
    "sql": "SELECT metadata->timestamp as timestamp, metadata->bort as vehicle_id, 'vibro' as sensor_type, CASE WHEN abs(data->weight - lag(data->weight, 1, 0)) >= 2.0 THEN 'active' ELSE 'inactive' END as status FROM local_stream_weight_ds GROUP BY TUMBLINGWINDOW(ss, 1)",
    "actions": [{
      "mqtt": {
        "server": "tcp://nanomq:1883",
        "topic": "truck/VEHICLE_ID_PLACEHOLDER/sensor/vibro/events",
        "qos": 0,
        "sendSingle": true,
        "dataTemplate": "{\"metadata\":{\"vehicle_id\":\"{{.vehicle_id}}\",\"sensor_type\":\"{{.sensor_type}}\",\"timestamp\":{{.timestamp}}},\"data\":{\"status\":\"{{.status}}\"}}"
      }
    }]
  }
